from collections import Counter

def most_frequent_word(text: str) -> str:
    words = text.split()
    if not words:
        raise ValueError("Empty input")
    counts = Counter(words)
    best_count = max(counts.values())
    for w in words:
        if counts[w] == best_count:
            return w
```

Counts word occurrences, then walks the original word order to return the first word achieving the max count.

